// =============================================
// SIMPLE WARMUP - NO SCHEDULE, NO RAMP
// Sends immediately, every trigger
// =============================================

const now = new Date();
const hour = now.getHours();

// Only check: are we within sending hours? (8 AM - 9 PM)
const isBusinessHours = hour >= 8 && hour <= 21;

// Daily counter
const staticData = $getWorkflowStaticData('global');
const today = now.toISOString().split('T')[0];
if (staticData.lastDate !== today) {
  staticData.lastDate = today;
  staticData.sentToday = 0;
}

// Max 30 emails per day to avoid Hostinger limits
const maxPerDay = 30;
const canSend = isBusinessHours && staticData.sentToday < maxPerDay;

return [{
  json: {
    canSend,
    sentToday: staticData.sentToday,
    maxPerDay,
    currentHour: hour,
    isBusinessHours
  }
}];

